    /// Lookup by (subject, grade). Returns the lesson for that bucket, or nil if
    /// the subject isn't taught at that grade in the Chinese K12 system.
    public static func lesson(subject: Subject, grade: GradeLevel) -> LessonScript? {
        lessons.first { $0.subject == subject && $0.grade == grade }
    }

    /// All lessons for a given subject across the grades it covers.
    public static func lessons(subject: Subject) -> [LessonScript] {
        lessons.filter { $0.subject == subject }.sorted { $0.grade.rawValue < $1.grade.rawValue }
    }

    /// Total count for sanity checks / progress reporting.
    public static var totalCount: Int { lessons.count }
}
